import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, BookOpen, Search } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminBooks = () => {
  const [books, setBooks] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  const fetchBooks = async () => {
    try {
      const res = await AdminService.getAllBooks();
      setBooks(res.data);
    } catch (err) { toast.error("Library Sync Error"); }
  };

  useEffect(() => { fetchBooks(); }, []);

  const filtered = books.filter(b => b.Title_English?.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase tracking-tighter italic">Library <span className="text-primary">Books</span></h1>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Literature Repository</p>
        </div>
        <Link to="/admin/books/add" className="bg-black text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-primary transition-all shadow-xl">
          <Plus size={16} /> Log Volume
        </Link>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
        <input 
          placeholder="Search publications..." 
          className="w-full pl-12 pr-4 py-4 bg-white rounded-2xl border border-gray-100 outline-none focus:ring-2 focus:ring-primary font-bold"
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="bg-white dark:bg-[#0f0f0f] rounded-[2.5rem] border border-gray-100 dark:border-white/5 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead className="bg-gray-50 dark:bg-white/5 border-b dark:border-white/10">
            <tr>
              <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-400">ID</th>
              <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-400">Title</th>
              <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-400 text-right">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-50 dark:divide-white/5">
            {filtered.map((book: any) => (
              <tr key={book._id} className="hover:bg-gray-50/50 transition-colors">
                <td className="px-8 py-6 font-black text-xs italic">{book.Book_ID}</td>
                <td className="px-8 py-6 font-bold text-xs uppercase">{book.Title_English}</td>
                <td className="px-8 py-6 text-right">
                  <button className="p-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all"><Trash2 size={16} /></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};
